import SunCalc from "suncalc"


const getData = (date, latitude, longitude) => {

  class Data{
    constructor(i, a){
      this.x=i
      this.y=a
    }
    data() {
      return {
        data:
        {x:this.x,y:this.y}
      }
    }
  }

  const getSunPos = () => {
    let dayString = String(date).substring(0,16)
    let data = []
    let temp
    for(let i = 0; i <=24; i++){
      let finalDate = new Date(dayString+i+':00:00 GMT+0100')
      var altitude = SunCalc.getPosition(finalDate, latitude, longitude).altitude * 180 / Math.PI
      temp = new Data(i, altitude)
      data.push(temp.data().data)
    }
    return data
  }

  var dataObj = [
    {
      id: 'Altitude',
      color: 'hsl(, 100%, 50%)',
      data: getSunPos(),
    },
  ]

  return dataObj
}

export {getData }
